INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BADMINTON
('badminton', 'Modern Origins', 'In which country were the modern rules of badminton first standardized?', 'multiple_choice', '["India", "China", "England", "Malaysia"]', 'England', 'The modern game was standardized at Badminton House, the estate of the Duke of Beaufort in Gloucestershire.'),
('badminton', 'Shuttlecock Feathers', 'A professional feather shuttlecock is traditionally made from the feathers of which wing of a goose?', 'multiple_choice', '["Right wing", "Left wing", "Both wings", "Tail feathers"]', 'Left wing', 'Feathers from the left wing are used to ensure the shuttlecock spins clockwise for stability.'),
('badminton', 'Olympic Debut', 'In which year did badminton become an official medal sport at the Olympic Games?', 'text', NULL, '1992', 'Badminton made its official debut at the 1992 Barcelona Olympics.'),
('badminton', 'Fastest Smash', 'The fastest recorded smash in professional badminton exceeds 500 km/h.', 'boolean', NULL, 'True', 'Satwiksairaj Rankireddy set a world record with a smash speed of 565 km/h in 2023.'),
('badminton', 'Service Height', 'What is the fixed height limit (in meters) for a legal serve in professional play?', 'text', NULL, '1.15', 'According to BWF rules, the entire shuttle must be below 1.15 meters at the point of impact.'),
('badminton', 'Thomas Cup', 'The Thomas Cup is the world team championship for which category?', 'multiple_choice', '["Women", "Mixed", "Men", "Juniors"]', 'Men', 'The Thomas Cup was donated by Sir George Thomas for the international men''s team competition.'),
('badminton', 'Scoring Ceiling', 'What is the absolute maximum score a single game can reach?', 'text', NULL, '30', 'If a game reaches 29-29, the first player to 30 points wins the game.'),
('badminton', 'Court Lines', 'In badminton, a shuttle landing on the boundary line is considered "out".', 'boolean', NULL, 'False', 'The lines are part of the court area; if any part of the shuttle touches the line, it is "in".'),
('badminton', 'Lee Chong Wei', 'Which country does the legendary player Lee Chong Wei represent?', 'text', NULL, 'Malaysia', 'Lee Chong Wei is a former world number one and a three-time Olympic silver medalist for Malaysia.'),
('badminton', 'Mixed Doubles', 'In mixed doubles, the female player typically spends most of her time at the back of the court.', 'boolean', NULL, 'False', 'Traditionally, the female player plays at the net to intercept shots while the male player covers the back.'),

-- MOBILE LEGENDS: BANG BANG
('mobile legends', 'Hero Titles', 'Which hero is known as the "Son of the Dragon"?', 'text', NULL, 'Zilong', 'Zilong is one of the original heroes and is the loyal disciple of the Great Dragon.'),
('mobile legends', 'Item Passive', 'Which item provides a passive called "Resurrect" to come back to life after death?', 'multiple_choice', '["Blade of Despair", "Immortal", "Winter Truncheon", "Athena''s Shield"]', 'Immortal', 'Immortality allows a hero to resurrect 2.5 seconds after death with a small shield.'),
('mobile legends', 'Laning Phase', 'Which lane is typically reserved for the "Marksman" role?', 'multiple_choice', '["Exp Lane", "Mid Lane", "Gold Lane", "Jungle"]', 'Gold Lane', 'The Gold Lane provides extra gold from siege minions, allowing Marksmen to buy items faster.'),
('mobile legends', 'Max Level', 'What is the maximum level a hero can reach in a standard match?', 'text', NULL, '15', 'Heroes cap out at level 15, which maximizes their skill points and base attributes.'),
('mobile legends', 'Retribution Spell', 'The Retribution battle spell is mandatory for the Jungler role.', 'boolean', NULL, 'True', 'Retribution is required to purchase Jungle equipment and effectively secure the Turtle and Lord.'),
('mobile legends', 'Lord Spawn', 'The Lord appears for the first time in the river at which minute mark?', 'text', NULL, '8', 'The Lord replaces the Turtle pit at exactly 8:00 minutes into the game.'),
('mobile legends', 'Hero Roles', 'Which hero can "possess" an ally to provide a massive shield?', 'text', NULL, 'Angela', 'Angela''s ultimate, Heartgard, allows her to attach to an ally and provide support from within.'),
('mobile legends', 'Draft Pick', 'In Epic rank and above, each team can ban up to how many heroes?', 'text', NULL, '5', 'The standard tournament and high-rank draft allow for a total of 10 bans (5 per team).'),
('mobile legends', 'True Damage', 'True damage ignores all physical and magic defense stats.', 'boolean', NULL, 'True', 'True damage bypasses all forms of defense, dealing its full value directly to the enemy HP.'),
('mobile legends', 'Map Name', 'What is the official name of the map used for 5v5 Rank matches?', 'text', NULL, 'The Land of Dawn', 'All standard competitive matches in MLBB take place in the Land of Dawn.'),

-- MIXED TOPICS (CONTINUING)
('badminton', 'Net Height', 'What is the height of the net at the center of the court?', 'multiple_choice', '["1.55m", "1.524m", "1.60m", "1.50m"]', '1.524m', 'The net is exactly 5 feet (1.524m) high at the center, though it is 1.55m at the posts.'),
('mobile legends', 'Hero Skills', 'Which hero uses "Cables" to swing between walls for high mobility?', 'text', NULL, 'Fanny', 'Fanny is famous for her "Steel Cable" skill, which makes her one of the hardest heroes to master.'),
('badminton', 'Strings', 'Higher string tension provides more power but less control.', 'boolean', NULL, 'False', 'Higher tension provides more control and "feel," while lower tension provides a "trampoline effect" for more power.'),
('mobile legends', 'Active Items', 'Which item makes the user immune to physical damage for a short duration?', 'multiple_choice', '["Windtalker", "Wind of Nature", "Golden Staff", "Rose Gold Meteor"]', 'Wind of Nature', 'Commonly known as "WON," it provides physical immunity, making it core for Marksmen.'),
('badminton', 'Shots', 'A "Clear" is a shot hit deep into the opponent''s backcourt.', 'boolean', NULL, 'True', 'The clear is used to push the opponent away from the net and reset the rally.'),
('mobile legends', 'Lore', 'Gusion is the brother of which other hero?', 'text', NULL, 'Aamon', 'Both are members of the House of Paxley, with Aamon being the elder brother.'),
('badminton', 'Grip Sizing', 'In the Yonex sizing system, is G5 larger or smaller than G4?', 'multiple_choice', '["Larger", "Smaller", "Same Size", "Depends on country"]', 'Smaller', 'In badminton handle sizing, a higher number indicates a smaller circumference.'),
('mobile legends', 'Rank Tiers', 'Which rank tier sits immediately below Mythic?', 'text', NULL, 'Legend', 'Players must progress through Legend I to V before reaching the Mythic rank.'),
('badminton', 'Scoring Interval', 'At what score do players have a 60-second break (interval)?', 'text', NULL, '11', 'The interval occurs when the first player or pair reaches 11 points.'),
('mobile legends', 'Battle Spells', 'The "Purify" spell can remove "Suppression" crowd control.', 'boolean', NULL, 'False', 'Suppression (like Franco''s Ultimate) is the only CC that cannot be removed by Purify.'),
('badminton', 'Double Hit', 'A player can hit the shuttle twice in one continuous stroke.', 'boolean', NULL, 'True', 'If the shuttle hits the frame and strings in one stroke, it is now legal under modern rules.'),
('mobile legends', 'Hero Skins', 'What is the highest rarity tier for skins found in the Magic Wheel?', 'text', NULL, 'Legend', 'Legend skins are the rarest and most expensive skins, often obtained via Magic Cores.'),
('badminton', 'Racket Material', 'Professional badminton rackets are mostly made of what material?', 'multiple_choice', '["Aluminum", "Steel", "Graphite/Carbon Fiber", "Wood"]', 'Graphite/Carbon Fiber', 'Modern rackets use high-modulus graphite for strength, flexibility, and lightness.'),
('mobile legends', 'Objectives', 'The "Turtle" buff provides a shield to the entire team.', 'boolean', NULL, 'False', 'While the gold/EXP is shared, only the person who slays the Turtle gets the shield/damage buff.'),
('badminton', 'Faults', 'Touching the net with your racket while the shuttle is in play is a fault.', 'boolean', NULL, 'True', 'Any part of the player or their racket touching the net results in a loss of the rally.'),
('mobile legends', 'Item Mechanics', 'Which item provides "True Damage" on basic attacks after using a skill?', 'multiple_choice', '["Endless Battle", "Blade of Despair", "War Axe", "Hunter Strike"]', 'Endless Battle', 'The "Divine Justice" passive makes Endless Battle essential for physical burst heroes.'),
('badminton', 'History', 'Badminton was once called "Poona" in India.', 'boolean', NULL, 'True', 'British officers brought the game back from Pune, India, where it was known as Poona.'),
('mobile legends', 'Hero Passives', 'Which hero gains "Stars" to increase her ultimate damage?', 'text', NULL, 'Chang''e', 'Chang''e’s mechanics revolve around her Crescent Moon and stacking damage for her Meteor Shower.'),
('badminton', 'Service Direction', 'In doubles, the serve must always be hit diagonally.', 'boolean', NULL, 'True', 'All legal serves in badminton must travel cross-court to the diagonal service area.'),
('mobile legends', 'Gameplay', 'What is the term for a team killing all five enemies at once?', 'text', NULL, 'Wiped Out', 'When every member of the opposing team is dead, the game announces "Wiped Out!".'),
('badminton', 'Technique', 'What is the name of the vertical jump used to hit a powerful smash?', 'multiple_choice', '["China Jump", "Scissors Kick", "Leap Step", "Split Step"]', 'Scissors Kick', 'The scissors kick is the footwork used in the air during a jump smash to maintain balance.'),
('mobile legends', 'Item Counters', 'Which item is the best counter to high Magic Burst damage (e.g., Eudora)?', 'multiple_choice', '["Radiant Armor", "Athena''s Shield", "Oracle", "Cursed Helmet"]', 'Athena''s Shield', 'Athena''s Shield provides a massive magic reduction shield when taking magic damage.'),
('badminton', 'Scoring', 'In the third game, players change ends when the score hits 11.', 'boolean', NULL, 'True', 'To ensure fairness in lighting or wind, players swap sides mid-way through the final set.'),
('mobile legends', 'Hero Passive', 'Which hero can "come back as an egg" after dying?', 'text', NULL, 'Diggie', 'Diggie’s passive allows him to move around as an egg and respawn at his current location.'),
('badminton', 'Famous Tournaments', 'The All England Open is the oldest badminton tournament in the world.', 'boolean', NULL, 'True', 'It was first held in 1899 and remains one of the most prestigious titles.'),
('mobile legends', 'Tower Shield', 'Turret shields disappear after how many minutes?', 'text', NULL, '5', 'The gold-granting shields on outer turrets expire at the 5-minute mark.'),
('badminton', 'Weight Rating', 'A 3U racket is lighter than a 4U racket.', 'boolean', NULL, 'False', 'In the "U" system, a lower number means a heavier racket (3U is approx 85-89g, 4U is 80-84g).'),
('mobile legends', 'Jungling', 'The "Blue Buff" reduces cooldowns and mana/energy consumption.', 'boolean', NULL, 'True', 'The Blue Buff (Thunder Fenrir) is vital for mana-hungry mages and energy-hungry assassins.'),
('badminton', 'Terminology', 'A "Let" is called when a rally is stopped and replayed.', 'boolean', NULL, 'True', 'A "Let" can be called for various reasons, such as a shuttle from another court flying in.'),
('mobile legends', 'Hero Weapon', 'Which hero uses a "Trident" as her primary weapon?', 'text', NULL, 'Kadita', 'Kadita is the Goddess of the Southern Sea and utilizes a trident for her skills.'),
('badminton', 'Badminton Asia', 'Which country currently holds the record for most Thomas Cup titles?', 'text', NULL, 'Indonesia', 'Indonesia is the most successful nation in Thomas Cup history with 14 titles.'),
('mobile legends', 'Equipment', 'Which item provides physical penetration based on the enemy''s physical defense?', 'multiple_choice', '["Malefic Roar", "Hunter Strike", "Heptaseas", "War Axe"]', 'Malefic Roar', 'Malefic Roar is the primary item for shredding high-defense tanks.'),
('badminton', 'Faults', 'It is legal to shout "Out!" while the shuttle is in the air to distract the opponent.', 'boolean', NULL, 'False', 'Making loud noises to distract an opponent is considered unsportsmanlike and is a fault.'),
('mobile legends', 'Ultimate Skill', 'Which hero’s ultimate is called "Real World Manipulation"?', 'text', NULL, 'Yve', 'Yve creates a star-grid on the screen where players must tap or slide to deal damage.'),
('badminton', 'History', 'Badminton is the second most popular participation sport in the world after soccer.', 'boolean', NULL, 'True', 'Especially in Asia, badminton is widely played at both recreational and professional levels.'),
('mobile legends', 'Battle Spell', 'The "Execute" spell deals true damage based on the target''s missing HP.', 'boolean', NULL, 'True', 'Execute is used to finish off enemies with low health by bypassing their remaining defense.'),
('badminton', 'Shuttlecock Durability', 'Synthetic (nylon) shuttlecocks are more durable than feather ones.', 'boolean', NULL, 'True', 'Nylon shuttles are preferred for beginners and recreational play due to their long life.'),
('mobile legends', 'Hero Origin', 'Which hero is known as the "Queen of the Abyss"?', 'text', NULL, 'Alice', 'Alice is the primary antagonist in many hero lore stories and leads the Abyssal forces.'),
('badminton', 'Scoring', 'If a match is 1-1 in games, the third game is played to 11 points.', 'boolean', NULL, 'False', 'The third game is played to the full 21 points, just like the first two.'),
('mobile legends', 'Gameplay', 'How many "Stars" are earned per win in the Mythic rank?', 'text', NULL, '1', 'In the current star-based system, each win provides one star toward the next milestone.');
INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 2: QUESTIONS 061 - 150
('badminton', 'Net Fault', 'A player wins the rally if their racket touches the net after the shuttle has hit the floor.', 'boolean', NULL, 'True', 'Once the shuttle is "dead" (hits the floor), the rally is over and net touches are no longer faults.'),
('mobile legends', 'Hero Passive', 'Which hero uses "Sword Intent" instead of Mana to cast skills?', 'text', NULL, 'Benedetta', 'Benedetta charges Sword Intent through basic attacks and holding her dash to perform special attacks.'),
('badminton', 'BWF World Tour', 'Which of these is the highest level of BWF World Tour tournaments?', 'multiple_choice', '["Super 300", "Super 500", "Super 750", "Super 1000"]', 'Super 1000', 'Super 1000 tournaments (like All England and China Open) offer the highest ranking points and prize money.'),
('mobile legends', 'Item Passive', 'The item "Lightning Truncheon" scales its bounce damage based on what?', 'multiple_choice', '["Magic Power", "Max Mana", "Max HP", "Current HP"]', 'Max Mana', 'Its passive Resonate deals extra magic damage that increases with the hero''s total mana pool.'),
('badminton', 'Service Rule', 'In doubles, the server must serve from the left court if their score is 10.', 'boolean', NULL, 'False', '10 is an even number; even scores always serve from the right service court.'),
('mobile legends', 'Hero Lore', 'Which hero is a "Time Traveler" from a ruined future?', 'text', NULL, 'Natan', 'Natan traveled back from a future destroyed by the Abyss to find a way to save the Land of Dawn.'),
('badminton', 'Racket Grip', 'What is the "Towel Grip" primarily made of?', 'multiple_choice', '["Rubber", "Synthetic Leather", "Cotton", "Polyurethane"]', 'Cotton', 'Towel grips are cotton-based and are preferred by players who sweat heavily for better absorption.'),
('mobile legends', 'Game Map', 'How many total turrets (towers) does one team have on the map?', 'text', NULL, '9', 'Each of the three lanes has 3 turrets (Outer, Inner, and Base), totaling 9 per team.'),
('badminton', 'Famous Players', 'Who is the first Singaporean to win the BWF World Championships in Men''s Singles?', 'text', NULL, 'Loh Kean Yew', 'Loh Kean Yew won the title in 2021 after defeating Srikanth Kidambi in the final.'),
('mobile legends', 'Item Passive', 'The "Golden Staff" item prevents the user from dealing critical hits.', 'boolean', NULL, 'True', 'Golden Staff converts every 1% of critical chance into 1% of attack speed instead.'),
('badminton', 'Shuttlecock Weight', 'What is the standard weight range of a feather shuttlecock?', 'multiple_choice', '["3.5 - 4.5g", "4.74 - 5.50g", "5.8 - 6.5g", "7.0 - 8.2g"]', '4.74 - 5.50g', 'Official BWF rules specify the shuttlecock must weigh between 4.74 and 5.50 grams.'),
('mobile legends', 'Hero Skills', 'Which hero can "copy" the Ultimate skill of an enemy?', 'text', NULL, 'Valentina', 'Valentina''s ultimate "I Am You" allows her to siphon and use the ultimate of a targeted enemy.'),
('badminton', 'Court Dimensions', 'A doubles court is wider than a singles court.', 'boolean', NULL, 'True', 'The doubles court includes the side "alleys," making it 6.1m wide compared to 5.18m for singles.'),
('mobile legends', 'Role Mechanics', 'A "Roamer" should avoid clearing minion waves alone in the early game.', 'boolean', NULL, 'True', 'Roamers have the "Devotion" passive which gives all minion gold/EXP to nearby allies instead of themselves.'),
('badminton', 'Technique', 'A "Drive" is a high, arching shot aimed at the backline.', 'boolean', NULL, 'False', 'A drive is a flat, fast shot hit horizontally over the net.'),
('mobile legends', 'Hero Passive', 'Which hero can "fly" over obstacles while using his ultimate "Black Dragon Form"?', 'text', NULL, 'Yu Zhong', 'Yu Zhong transforms into a dragon, gaining crowd control immunity and the ability to fly over walls.'),
('badminton', 'Service Judge', 'The Service Judge signals a "high serve" fault by extending their arm horizontally.', 'boolean', NULL, 'False', 'A height fault (above 1.15m) is signaled by holding a hand horizontally at the chest.'),
('mobile legends', 'Item Counter', 'Which item is best for countering high Physical Lifesteal (e.g., Alucard)?', 'multiple_choice', '["Blade Armor", "Dominance Ice", "Antique Cuirass", "Twilight Armor"]', 'Dominance Ice', 'Dominance Ice reduces the shield and HP regen of nearby enemies by 50%.'),
('badminton', 'Famous Events', 'The "Sudirman Cup" is a world championship for mixed teams.', 'boolean', NULL, 'True', 'It features men''s and women''s singles, doubles, and mixed doubles to determine the best overall nation.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Marksman" that uses a "Sniper" and a "Shotgun"?', 'text', NULL, 'Beatrix', 'Beatrix has four weapons: Renner (Sniper), Wesker (Shotgun), Bennett (Grenade), and Nibiru (SMG).'),
('badminton', 'Racket Balance', 'A "Head-Heavy" racket is generally preferred by defensive players.', 'boolean', NULL, 'False', 'Head-heavy rackets are better for offensive smashing; defensive players prefer "Head-Light" for speed.'),
('mobile legends', 'Game Mechanics', 'What does "DPS" stand for?', 'text', NULL, 'Damage Per Second', 'DPS refers to the consistent, sustained damage a hero can output over time.'),
('badminton', 'History', 'Badminton made its debut as a "Demonstration Sport" in which year?', 'text', NULL, '1972', 'It was a demonstration sport in 1972 and 1988 before becoming a full medal sport in 1992.'),
('mobile legends', 'Item Passive', 'Which item provides extra Physical Penetration as the enemy builds more Physical Defense?', 'multiple_choice', '["Malefic Roar", "Hunter Strike", "Heptaseas", "War Axe"]', 'Malefic Roar', 'Malefic Roar provides a percentage of penetration that increases with the target''s armor.'),
('badminton', 'Faults', 'If the shuttle hits the ceiling, it is considered a fault.', 'boolean', NULL, 'True', 'The shuttle is considered out of bounds if it touches any permanent fixture or the ceiling.'),
('mobile legends', 'Hero Lore', 'Who is the "Princess" of the Moniyan Empire?', 'text', NULL, 'Silvanna', 'Silvanna is the imperial princess who took up the lance to protect her kingdom and find her lost brother.'),
('badminton', 'Technique', 'What is the "Panhandle Grip" mostly used for?', 'multiple_choice', '["High Clears", "Smashes", "Net Kills", "Backhand Defense"]', 'Net Kills', 'The panhandle grip allows for a quick tapping motion, ideal for finishing points at the net.'),
('mobile legends', 'Objectives', 'The "Lord" becomes "Enhanced" at the 12-minute mark.', 'boolean', NULL, 'True', 'At 12 minutes, the Lord gains higher attributes and the ability to charge at turrets.'),
('badminton', 'Service Rule', 'Can the server’s feet move during the service?', 'boolean', NULL, 'No', 'Both the server and receiver must have their feet stationary on the ground until the serve is struck.'),
('mobile legends', 'Hero Skills', 'Which hero has an ultimate that "shuts down the lights" (blinds the map)?', 'text', NULL, 'Helcurt', 'Helcurt''s "Dark Night Falls" ultimate blinds all enemy heroes and removes their vision.'),
('badminton', 'Racket Strings', 'Thinner strings generally provide more "repulsion" and power.', 'boolean', NULL, 'True', 'Thinner strings (e.g., 0.65mm) offer more bounce/repulsion, though they are less durable.'),
('mobile legends', 'Item Passive', 'The "Cursed Helmet" deals damage to nearby enemies based on what?', 'multiple_choice', '["Physical Attack", "Max HP", "Missing HP", "Magic Power"]', 'Max HP', 'It deals a percentage of the wearer''s Max HP as Magic Damage to nearby enemies.'),
('badminton', 'Terminology', 'A "Wood Shot" is when the shuttle hits the frame of the racket.', 'boolean', NULL, 'True', 'In modern badminton, a wood shot is legal as long as it is a single, continuous hit.'),
('mobile legends', 'Hero Mechanics', 'Faramis can "resurrect" teammates temporarily using his Ultimate.', 'boolean', NULL, 'True', 'His "Cult Altar" ultimate provides a temporary extra life state to teammates in its range.'),
('badminton', 'Double Strategy', 'In an "Attacking Formation," partners stand side-by-side.', 'boolean', NULL, 'False', 'In attack, partners stand "Front and Back" to maximize downward pressure.'),
('mobile legends', 'Hero Passive', 'Which hero gains "Shield" every time they use a skill that hits an enemy?', 'text', NULL, 'Esmeralda', 'Esmeralda generates shields for herself while also siphoning shields from her enemies.'),
('badminton', 'History', 'Where is the Badminton World Federation (BWF) currently headquartered?', 'multiple_choice', '["London", "Beijing", "Jakarta", "Kuala Lumpur"]', 'Kuala Lumpur', 'The BWF moved its headquarters from England to Malaysia in 2005.'),
('mobile legends', 'Battle Spell', 'The "Aegis" spell provides a shield to the user and their lowest-HP ally nearby.', 'boolean', NULL, 'True', 'Aegis is a protective spell used to save teammates or oneself from burst damage.'),
('badminton', 'Technique', 'The "Cross-court Drop" travels a longer distance than a straight drop.', 'boolean', NULL, 'True', 'Because it travels diagonally across the full width of the court, it has a longer flight path.'),
('mobile legends', 'Hero Weapons', 'Which hero uses "Fans" to fight and manipulate shadows?', 'text', NULL, 'None', 'While Kagura uses an umbrella and Hanabi uses a Higanbana, no current hero uses fans as a base weapon.'),
('badminton', 'Line Judge', 'A line judge signals a shuttle is "in" by extending both arms horizontally.', 'boolean', NULL, 'False', 'A line judge signals "in" by pointing their arm toward the line.');
INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 3: QUESTIONS 102 - 200
('badminton', 'Umpire Call', 'What does the umpire say when the server has won the first point of the match?', 'text', NULL, '1-0', 'The umpire announces the server''s score first, followed by the receiver''s score.'),
('mobile legends', 'Hero Mechanics', 'Which hero can "possess" a turret to protect it and deal damage?', 'text', NULL, 'None', 'While Edith and Gloo have possession-like mechanics, no hero can currently merge with or possess a turret.'),
('badminton', 'Shuttlecock Physics', 'A shuttlecock flies faster in a warm hall than in a cold hall.', 'boolean', NULL, 'True', 'Warm air is less dense, which reduces aerodynamic drag and allows the shuttle to travel faster.'),
('mobile legends', 'Item Passive', 'The item "Fleeting Time" reduces the cooldown of which specific skill type upon a kill or assist?', 'multiple_choice', '["Passive", "First Skill", "Second Skill", "Ultimate"]', 'Ultimate', 'The Timestream passive specifically targets the Ultimate''s cooldown, making it core for heroes like Angela or Kadita.'),
('badminton', 'Technique', 'The "Split Step" is a footwork move performed just as the opponent hits the shuttle.', 'boolean', NULL, 'True', 'The split step unweights the feet, allowing the player to react and push off in any direction instantly.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Astro Warden"?', 'text', NULL, 'Yve', 'Yve is a cosmic being tasked with hunting down her rival, Zhask.'),
('badminton', 'Racket Tension', 'Professional players typically use a lower string tension than recreational players.', 'boolean', NULL, 'False', 'Professionals use high tension (28-35 lbs) for precision, while beginners use low tension (20-24 lbs) for easy power.'),
('mobile legends', 'Game Objectives', 'The "Turtle" will stop spawning after which minute mark in the game?', 'text', NULL, '8', 'The Turtle disappears at 8:00 to make way for the Lord.'),
('badminton', 'Famous Players', 'Viktor Axelsen is a legendary singles player from which country?', 'text', NULL, 'Denmark', 'Axelsen is a multiple-time World Champion and Olympic Gold medalist from Denmark.'),
('mobile legends', 'Item Passive', 'Which item allows a hero to deal "Burn" damage to enemies over time after hitting them with magic?', 'multiple_choice', '["Holy Crystal", "Glowing Wand", "Blood Wings", "Genius Wand"]', 'Glowing Wand', 'The Scorch passive deals magic damage equal to a percentage of the target''s Max HP over 3 seconds.'),
('badminton', 'Service Court', 'In singles, if the server''s score is 21, they serve from which side?', 'multiple_choice', '["Right", "Left", "Center", "Back"]', 'Left', 'Odd numbers (1, 3, 5... 21) serve from the left court in badminton.'),
('mobile legends', 'Hero Skills', 'Which hero transforms into a "Black Dragon" for his Ultimate?', 'text', NULL, 'Yu Zhong', 'Yu Zhong''s Black Dragon form allows him to ignore terrain and apply pressure to backline enemies.'),
('badminton', 'Court Lines', 'The "Short Service Line" is common to both singles and doubles play.', 'boolean', NULL, 'True', 'All legal serves must cross the short service line to be considered "in".'),
('mobile legends', 'Hero Passive', 'Which hero has a passive that lets them "Resurrect" as a small cat-like creature?', 'text', NULL, 'Nana', 'Nana''s "Molina''s Blessing" triggers upon taking fatal damage, transforming her and making her untargetable.'),
('badminton', 'Match Structure', 'What is the maximum number of games played in a standard BWF match?', 'text', NULL, '3', 'Badminton matches are played in a best-of-three format.'),
('mobile legends', 'Item Counter', 'Which item is the most effective counter against "True Damage"?', 'multiple_choice', '["Blade Armor", "Guardian Helmet", "Antique Cuirass", "Athena''s Shield"]', 'Guardian Helmet', 'True damage ignores defense, so the only way to counter it is by building a large pool of Max HP.'),
('badminton', 'History', 'Which country has won the most "Uber Cup" titles?', 'text', NULL, 'China', 'China has historically dominated the women''s team world championship.'),
('mobile legends', 'Hero Roles', 'A "Jungler" should always prioritize the "Turtle" to gain team-wide gold and EXP.', 'boolean', NULL, 'True', 'Securing the Turtle is one of the Jungler''s primary objectives to give their team an early lead.'),
('badminton', 'Racket Parts', 'The part of the racket that connects the handle to the frame is called the:', 'multiple_choice', '["Head", "Shaft", "String", "Grip"]', 'Shaft', 'The shaft determines the flexibility and power transfer of the racket.'),
('mobile legends', 'Hero Weapons', 'Which hero uses "Cables" to pull himself towards walls but is a Tank?', 'text', NULL, 'None', 'Fanny uses cables but is an Assassin. Grock interacts with walls but does not use cables.'),
('badminton', 'Service Fault', 'It is a fault if the server strikes the shuttle while it is above their waist level.', 'boolean', NULL, 'True', 'Modern BWF rules require the shuttle to be below 1.15m at the point of impact.'),
('mobile legends', 'Item Passive', 'What is the maximum number of stacks for the "War Axe" item?', 'text', NULL, '8', 'War Axe provides increasing physical attack and penetration, peaking at 8 stacks.'),
('badminton', 'Tournament Types', 'The "Thomas Cup" is an individual tournament for men''s singles.', 'boolean', NULL, 'False', 'The Thomas Cup is the world team championship for men.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Spear of Dragon"?', 'text', NULL, 'Zilong', 'Zilong was once named Yun Zhao and is the commander of the Great Dragon''s forces.'),
('badminton', 'Technique', 'A "Net Kill" is hit with a very long, high follow-through.', 'boolean', NULL, 'False', 'A net kill requires a short, sharp snap to avoid hitting the net with the racket.'),
('mobile legends', 'Battle Spell', 'The "Retribution" spell damage increases as the Jungler levels up.', 'boolean', NULL, 'True', 'Retribution damage scales with the hero''s level, helping them secure objectives in the late game.'),
('badminton', 'Equipment', 'A "Synthetic" shuttlecock is usually made from what material?', 'multiple_choice', '["Rubber", "Nylon", "Plastic", "Polyester"]', 'Nylon', 'Nylon shuttlecocks are the industry standard for recreational and training play.'),
('mobile legends', 'Hero Lore', 'Gusion belongs to which noble family?', 'text', NULL, 'Paxley', 'Gusion is the fourth son of the Paxley family, a lineage of powerful mages.'),
('badminton', 'Technique', 'The "Forehand Clear" is intended to land in the opponent''s midcourt.', 'boolean', NULL, 'False', 'A clear is intended to land as deep as possible in the opponent''s backcourt.'),
('mobile legends', 'Item Passive', 'Which item provides the "Unique Passive: Devour," dealing damage based on the target''s current HP?', 'multiple_choice', '["Endless Battle", "Demon Hunter Sword", "Corrosion Scythe", "Golden Staff"]', 'Demon Hunter Sword', 'DHS deals 9% of the target''s current HP as extra physical damage, making it a "Tank Killer".'),
('badminton', 'Service Fault', 'Is it a fault if the server misses the shuttle entirely while trying to serve?', 'boolean', NULL, 'True', 'If the server swings and misses the shuttle, it is recorded as a service fault.'),
('mobile legends', 'Hero Passive', 'Which hero can "move through walls" while in their shadow form?', 'text', NULL, 'Hanzo', 'Hanzo''s ultimate "Kinjutsu: Pinnacle Ninja" sends his soul out, which can traverse any terrain.'),
('badminton', 'Scoring', 'If the score reaches 29-29, the next person to score wins the game.', 'boolean', NULL, 'True', '30 points is the absolute cap in badminton scoring.'),
('mobile legends', 'Map Objectives', 'Destroying the "Base Turret" (Tier 3) spawns "Super Minions" in that lane.', 'boolean', NULL, 'True', 'Super Minions have significantly higher HP and damage than regular minions.'),
('badminton', 'Racket Rating', 'Racket weight "4U" is heavier than "3U".', 'boolean', NULL, 'False', 'In the "U" system, 3U (85-89g) is heavier than 4U (80-84g).'),
('mobile legends', 'Hero Lore', 'Who is the "Queen of the Northern Vale"?', 'text', NULL, 'Aurora', 'Aurora is the powerful frost mage who guards the frozen northern territories.'),
('badminton', 'History', 'Where was the first "All England" championship held?', 'text', NULL, 'London', 'The inaugural All England Open took place at the Buckingham Gate Drill Hall in 1899.'),
('mobile legends', 'Gameplay', 'The "Gold Lane" siege minion provides extra experience points.', 'boolean', NULL, 'False', 'The Gold Lane siege minion provides extra gold; the Exp Lane siege minion provides extra experience.'),
('badminton', 'Technique', 'The "Scissors Kick" is a footwork pattern used for which shot?', 'multiple_choice', '["Net Drop", "Backhand Drive", "Jump Smash", "Short Serve"]', 'Jump Smash', 'The scissors kick allows the player to swap legs in mid-air to generate power and land ready for the next shot.'),
('mobile legends', 'Hero Passive', 'Which hero can "link" enemies together to share damage?', 'text', NULL, 'Carmilla', 'Carmilla''s ultimate "Curse of Blood" links enemies so they share a percentage of damage and CC received.'),
('badminton', 'Shuttlecock', 'How many feathers are on a standard professional shuttlecock?', 'text', NULL, '16', 'All BWF-approved shuttlecocks must have exactly 16 feathers.'),
('mobile legends', 'Item Passive', 'Which item provides "Physical Penetration" based on the target''s physical defense?', 'multiple_choice', '["Blade of Heptaseas", "Hunter Strike", "Malefic Roar", "War Axe"]', 'Malefic Roar', 'Malefic Roar increases penetration by 0.05% for every point of the enemy''s defense.'),
('badminton', 'Rule Fault', 'It is a fault if the shuttle hits the player''s body before hitting the ground.', 'boolean', NULL, 'True', 'The shuttle must only touch the racket; touching the body or clothing is a fault.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Desert Tyrant"?', 'text', NULL, 'Khufra', 'Khufra was once the ruler of the Western Desert before being sealed away.'),
('badminton', 'History', 'Badminton was once a part of the "Commonwealth Games" before it was in the Olympics.', 'boolean', NULL, 'True', 'It was first included in the Commonwealth Games in 1966.'),
('mobile legends', 'Gameplay', 'What is the term for "hiding in a bush" to ambush enemies?', 'text', NULL, 'Ganking', 'While ganking is the overall act of ambushing, "camping" is often used for waiting in bushes.'),
('badminton', 'Famous Players', 'Lee Chong Wei won how many Olympic Gold medals?', 'text', NULL, '0', 'Lee Chong Wei won three silver medals but never secured the gold.'),
('mobile legends', 'Item Passive', 'The item "Winter Truncheon" provides "Magic Power" and what other defensive stat?', 'multiple_choice', '["Magic Defense", "Physical Defense", "HP", "Mana Regen"]', 'Physical Defense', 'It provides +25 Physical Defense along with its magic stats and active "freeze" skill.'),
('badminton', 'Double Rule', 'In doubles, the partners must take turns hitting the shuttle.', 'boolean', NULL, 'False', 'Unlike table tennis, any partner can hit the shuttle as long as they only hit it once per turn.'),
('mobile legends', 'Hero Passive', 'Which hero gains "Armor" and "Magic Resist" every time they lose HP?', 'text', NULL, 'Hilda', 'Actually, Hilda heals in bushes; Argus becomes immune to death. This specific passive is most similar to Barats or Terizla.'),
('badminton', 'Court Surface', 'What is the standard material for professional badminton mats?', 'text', NULL, 'PVC', 'Professional courts use synthetic PVC mats for optimal grip and shock absorption.');
INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 4: QUESTIONS 201 - 300
('badminton', 'Umpire Signals', 'When a player touches the net while the shuttle is in play, what fault does the Umpire call?', 'text', NULL, 'Net Fault', 'Touching the net with the body or racket before the point is over is a Net Fault.'),
('mobile legends', 'Hero Roles', 'Which hero is known as the "Ocean Gladiator" and uses an anchor?', 'text', NULL, 'Atlas', 'Atlas is a spirit inhabiting an ancient mechanical suit from the Abyssal Sea.'),
('badminton', 'Shuttlecock Color', 'Standard competition shuttlecocks are always white.', 'boolean', NULL, 'True', 'While recreational shuttles can be yellow, professional BWF-sanctioned shuttles must be white.'),
('mobile legends', 'Item Passive', 'Which item provides the "Unique Passive: Mark," increasing damage dealt to the target by teammates?', 'multiple_choice', '["Courage Mask", "None", "Great Dragon Spear", "Fleeting Time"]', 'None', 'The "Mask" items were removed; current items focus on personal buffs or utility rather than teammate-wide damage marks.'),
('badminton', 'Court Dimensions', 'What is the total length of the badminton court for both singles and doubles?', 'text', NULL, '13.4m', 'The court length is a standard 13.4 meters (44 feet) for all professional matches.'),
('mobile legends', 'Hero Passive', 'Which hero transforms from a "Tank" into a "Marksman" during her Ultimate?', 'text', NULL, 'Edith', 'Edith ejects from her mecha suit, Phylax, to deal massive magic damage as a ranged marksman.'),
('badminton', 'Racket Weight', 'A 5U racket is heavier than a 3U racket.', 'boolean', NULL, 'False', '5U rackets are lighter (75-79g) compared to 3U rackets (85-89g).'),
('mobile legends', 'Battle Spell', 'The "Inspire" spell increases attack speed and ignores a portion of physical defense.', 'boolean', NULL, 'True', 'Inspire is used to maximize the damage output of basic attack-reliant heroes like marksmen.'),
('badminton', 'Famous Tournaments', 'The Sudirman Cup is held every how many years?', 'text', NULL, '2', 'The Sudirman Cup (World Mixed Team Championships) is a biennial event held every two years.'),
('mobile legends', 'Item Passive', 'Which item is best for physical assassins to increase damage against "low HP" targets?', 'multiple_choice', '["Blade of Heptaseas", "Blade of Despair", "Malefic Roar", "Hunter Strike"]', 'Blade of Despair', 'Its passive increases Physical Attack by 25% when attacking enemies with HP below 50%.'),
('badminton', 'Service Area', 'In doubles, the "Long Service Line" is the same as the back boundary line.', 'boolean', NULL, 'False', 'In doubles, the serve is "short and wide"; it cannot go past the inner back line (long service line).'),
('mobile legends', 'Hero Lore', 'Which hero is a "Blacksmith" who was imprisoned by the Moniyan Empire?', 'text', NULL, 'Terizla', 'Terizla is the leader of the smiths who was tortured and seeks revenge on the empire.'),
('badminton', 'Technique', 'What is the "Hairpin" net shot?', 'text', NULL, 'A shot hit close to the net that drops straight down', 'It is called a hairpin because the shuttle travels up and over the net in a very tight "U" shape.'),
('mobile legends', 'Game Mechanics', 'What is the "Active" skill name of the "Conceal" roaming blessing?', 'text', NULL, 'Conceal', 'It makes the user and nearby allies invisible and increases movement speed for a short duration.'),
('badminton', 'Racket Tension', 'Higher string tension results in a smaller "Sweet Spot".', 'boolean', NULL, 'True', 'While high tension offers more control, the area of the string bed that produces maximum power shrinks.'),
('mobile legends', 'Hero Passive', 'Which hero has a passive that allows them to "Leap" after every basic attack or skill?', 'text', NULL, 'Wanwan', 'Wanwan''s high mobility comes from her "Tiger Pace" passive, allowing her to dash constantly.'),
('badminton', 'Match Official', 'Who has the final say on the legality of a tournament venue?', 'multiple_choice', '["Umpire", "Service Judge", "Referee", "Line Judge"]', 'Referee', 'The Referee is in overall charge of the tournament, including the venue and schedule.'),
('mobile legends', 'Item Passive', 'Which item provides the highest "Attack Speed" in the game?', 'multiple_choice', '["Windtalker", "Golden Staff", "Corrosion Scythe", "Demon Hunter Sword"]', 'Golden Staff', 'Golden Staff provides +65% attack speed at its peak, making it the highest single-item speed boost.'),
('badminton', 'Service Fault', 'It is a fault if the server steps on the line during the service.', 'boolean', NULL, 'True', 'The server must remain entirely within the boundaries of the service court.'),
('mobile legends', 'Hero Passive', 'Which hero can "resurrect" once after dying thanks to their passive?', 'text', NULL, 'Nana', 'Molina''s Blessing allows Nana to survive a fatal hit and escape in a transformed state.'),
('badminton', 'Physics', 'A shuttlecock rotates (spins) while in flight.', 'boolean', NULL, 'True', 'The overlapping arrangement of the feathers causes the shuttle to spin clockwise to stabilize its flight.'),
('mobile legends', 'Hero Weapons', 'Which hero uses "Fists" and has an Ultimate called "Fist of Zen"?', 'text', NULL, 'Badang', 'Badang is the tribal warrior who uses powerful punches and creates walls to trap enemies.'),
('badminton', 'Tournament Points', 'Winning a BWF Super 1000 tournament grants how many ranking points?', 'text', NULL, '12000', 'Super 1000 tournaments are the highest tier in the regular BWF World Tour cycle.'),
('mobile legends', 'Item Passive', 'Which item provides "Physical Penetration" and increases movement speed after a kill?', 'multiple_choice', '["Hunter Strike", "War Axe", "Heptaseas", "None"]', 'None', 'Hunter Strike provides speed after 5 hits, and War Axe provides speed at max stacks; no item gives speed "after a kill" specifically.'),
('badminton', 'Faults', 'If the shuttle touches the net and falls into the opponent''s court during a serve, it is a "let".', 'boolean', NULL, 'False', 'Unlike tennis, if the shuttle hits the net but goes over and into the correct court, the serve is valid.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Shadow of Kindness"?', 'text', NULL, 'Benedetta', 'Despite her rough exterior, she protects the people of Lantis Canyon from the Abyss.'),
('badminton', 'Technique', 'The "Deceptive" drop shot is hit with a slow arm movement.', 'boolean', NULL, 'False', 'A deceptive drop uses a fast arm swing to look like a smash, but slows down at the last second.'),
('mobile legends', 'Game Map', 'How many "Small Jungles" (non-buff creeps) are on one side of the map?', 'text', NULL, '2', 'Excluding the Red and Blue buffs, each side has two small camps (Beetle and Lizard).'),
('badminton', 'Scoring', 'If the score is 20-20, a player wins if they reach 22-20.', 'boolean', NULL, 'True', 'In a deuce, a player must lead by 2 points to win.'),
('mobile legends', 'Item Passive', 'The "Guardian Helmet" restores HP based on what percentage of Max HP while out of combat?', 'multiple_choice', '["1.5%", "2.5%", "5.0%", "10%"]', '2.5%', 'It provides massive sustain for tanks, allowing them to heal without returning to base.'),
('badminton', 'Double Strategy', 'In defense, partners should stand side-by-side.', 'boolean', NULL, 'True', 'This allows each partner to cover their half of the court against smashes.'),
('mobile legends', 'Hero Skills', 'Which hero has an Ultimate called "I Am You"?', 'text', NULL, 'Valentina', 'This ultimate allows her to copy the appearance and ultimate skill of her enemy.'),
('badminton', 'History', 'Badminton was derived from an ancient game called "Battledore and Shuttlecock".', 'boolean', NULL, 'True', 'The original game was played with wooden paddles and dates back over 2,000 years.'),
('mobile legends', 'Item Passive', 'Which item provides "True Damage" based on Magic Power?', 'multiple_choice', '["Starlium Scythe", "Holy Crystal", "Blood Wings", "Glowing Wand"]', 'Starlium Scythe', 'Following the item merge, Starlium Scythe is the go-to for mages wanting true damage on basic attacks.'),
('badminton', 'Racket Grip', 'An "Overgrip" is applied directly onto the wood handle.', 'boolean', NULL, 'False', 'Overgrips are thin wraps applied over the original factory grip.'),
('mobile legends', 'Hero Passive', 'Which hero "floats" and does not have a walking animation?', 'text', NULL, 'Chang''e', 'Chang''e rides her Crescent Moon, and several other heroes like Pharsa also float.'),
('badminton', 'Terminology', 'What is a "Wood Shot"?', 'text', NULL, 'Hitting the shuttle with the frame of the racket', 'Once a fault, it is now legal as long as it was a single, non-deliberate hit.'),
('mobile legends', 'Hero Lore', 'Which hero was created by Dr. Rooney to be the ultimate weapon?', 'text', NULL, 'Alpha', 'Alpha and his twin Beta were creations of Laboratory 1718.'),
('badminton', 'Shuttlecock', 'How many feathers are in a standard BWF-sanctioned shuttlecock?', 'text', NULL, '16', 'All professional shuttles must consist of exactly 16 feathers.'),
('mobile legends', 'Item Passive', 'Which item provides the highest "Physical Penetration" in the game?', 'multiple_choice', '["Hunter Strike", "Heptaseas", "Malefic Roar", "War Axe"]', 'Malefic Roar', 'Malefic Roar provides 20% base penetration plus a bonus based on the enemy''s defense.'),
('badminton', 'Line Judge', 'A Line Judge signals "Out" by extending both arms horizontally.', 'boolean', NULL, 'True', 'This is the universal signal used by line judges in BWF tournaments.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Mage" whose ultimate is "Starfall"?', 'text', NULL, 'None', 'Chang''e has "Meteor Shower"; there is no hero with an ultimate called "Starfall".'),
('badminton', 'History', 'Where is the BWF Headquarters located?', 'text', NULL, 'Kuala Lumpur', 'The headquarters of the Badminton World Federation is in Kuala Lumpur, Malaysia.'),
('mobile legends', 'Game Mechanics', 'How many "stars" are needed to reach "Mythic Glory" from the base Mythic rank?', 'text', NULL, '50', 'Players must accumulate 50 stars to be promoted to the Mythic Glory tier.'),
('badminton', 'Scoring', 'Is it possible for a badminton game to end with a score of 30-29?', 'boolean', NULL, 'True', 'Yes, 30-29 is the final possible score if the game is tied at 29-29.'),
('mobile legends', 'Hero Passive', 'Which hero gains "Movement Speed" when they are in a bush?', 'text', NULL, 'Hilda', 'Hilda''s passive allows her to regenerate HP and gain a shield while in a bush.'),
('badminton', 'Technique', 'What is "Deception" in badminton?', 'text', NULL, 'Making one shot look like another', 'Deception is a key skill where players use wrist movements to trick the opponent.'),
('mobile legends', 'Item Counter', 'Which item is best for physical heroes to counter high "Shield" heroes?', 'multiple_choice', '["Sea Halberd", "Malefic Roar", "Blade of Despair", "Rose Gold Meteor"]', 'Sea Halberd', 'Sea Halberd reduces both HP regen and shield effectiveness.'),
('badminton', 'Rule Fault', 'A player can reach over the net to hit the shuttle before it crosses to their side.', 'boolean', NULL, 'False', 'The shuttle must cross the plane of the net before the player can strike it.'),
('mobile legends', 'Hero Passive', 'Which hero uses "Cables" but is an "Assassin"?', 'text', NULL, 'Fanny', 'Fanny is the only hero with the cable-swinging mechanic.'),
('badminton', 'Shuttlecock Durability', 'Feather shuttlecocks are generally more durable than synthetic ones.', 'boolean', NULL, 'False', 'Feather shuttles are fragile and often break within a few rallies; synthetic shuttles last longer.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Goddess of the Moon"?', 'text', NULL, 'Chang''e', 'In MLBB lore, Chang''e is the disciple of the Great Dragon but is themed after the moon goddess.'),
('badminton', 'Technique', 'The "Cross-court Drop" travels a shorter distance than a straight drop.', 'boolean', NULL, 'False', 'Diagonals are always longer than straight lines on a rectangular court.'),
('mobile legends', 'Item Passive', 'Which item provides "Attack Speed" and "Movement Speed"?', 'multiple_choice', '["Windtalker", "Golden Staff", "Corrosion Scythe", "All of the above"]', 'All of the above', 'All these items provide varying amounts of attack and movement speed stats.'),
('badminton', 'Scoring', 'In a 21-point game, players change ends when the score is 11.', 'boolean', NULL, 'True', 'This swap happens in all three games of a match.'),
('mobile legends', 'Hero Passive', 'Which hero "transforms" into a car for his Ultimate?', 'text', NULL, 'Johnson', 'Johnson''s ultimate allows him to carry a teammate and crash into enemies.'),
('badminton', 'Tournament', 'The "All England" is a Super 1000 tournament.', 'boolean', NULL, 'True', 'It is one of the four Super 1000 events in the current BWF World Tour.'),
('mobile legends', 'Item Passive', 'The item "Immortality" has a cooldown of 210 seconds.', 'boolean', NULL, 'True', 'This prevents players from resurrecting too frequently in the late game.'),
('badminton', 'Terminology', 'A "Kill" is a fast, downward shot hit from the net area.', 'boolean', NULL, 'True', 'Also called a "Net Kill," it is intended to end the rally immediately.'),
('mobile legends', 'Hero Weapons', 'Which hero uses a "Grappling Hook" to pull enemies?', 'text', NULL, 'Franco', 'Franco''s "Iron Hook" is his most iconic skill for catching out-of-position enemies.'),
('badminton', 'Shuttlecock', 'How many "Feathers" are in a standard shuttlecock?', 'text', NULL, '16', 'BWF regulations mandate exactly 16 feathers.'),
('mobile legends', 'Hero Passive', 'Which hero can "Summon" a monkey to fight alongside them?', 'text', NULL, 'Sun', 'Sun can create doppelgangers that inherit a portion of his attributes.'),
('badminton', 'Double Strategy', 'In mixed doubles, the man usually plays the backcourt.', 'boolean', NULL, 'True', 'This allows the man to use his power for smashes while the woman intercepts at the net.'),
('mobile legends', 'Hero Passive', 'Which hero "eats" enemies for his Ultimate?', 'text', NULL, 'Barats', 'Barats'' ultimate, "Detona''s Welcome," allows him to devour an enemy and spit them out.'),
('badminton', 'Scoring', 'Can a badminton match end with a score of 2-0?', 'boolean', NULL, 'True', 'If a player wins the first two games, the third game is not played.'),
('mobile legends', 'Item Passive', 'Which item provides "Lifesteal" for Physical damage?', 'multiple_choice', '["Haas'' Claws", "Holy Crystal", "Enchanted Talisman", "Oracle"]', 'Haas'' Claws', 'Haas'' Claws is the primary item for physical lifesteal sustain.'),
('badminton', 'Racket Grip', 'A "G5" grip is smaller than a "G4" grip.', 'boolean', NULL, 'True', 'In badminton, higher G-numbers indicate smaller handle circumferences.'),
('mobile legends', 'Hero Lore', 'Who is the "King of Fire" and brother of Valir?', 'text', NULL, 'Vale', 'Vale and Valir are iconic elemental heroes with deep-rooted lore rivalries.'),
('badminton', 'Court Lines', 'Is the "Alley" part of the court in singles play?', 'boolean', NULL, 'False', 'The side alleys are only used for doubles play; in singles, they are "out".'),
('mobile legends', 'Item Passive', 'The item "Dominance Ice" reduces enemy "Attack Speed".', 'boolean', NULL, 'True', 'It is a core defensive item used to counter high-attack-speed marksmen.'),
('badminton', 'Rule Fault', 'Is it a fault if the shuttle hits the net post?', 'boolean', NULL, 'True', 'The net post is considered a permanent fixture outside the court boundaries.'),
('mobile legends', 'Game Mechanics', 'What is the "Execute" spell used for?', 'text', NULL, 'Finishing off low-HP enemies', 'Execute deals true damage based on the enemy''s missing health.'),
('badminton', 'Famous Players', 'Who is the "King of the Backhand"?', 'text', NULL, 'Taufik Hidayat', 'The Indonesian legend was world-famous for his powerful and precise backhand smash.'),
('mobile legends', 'Hero Passive', 'Which hero "floats" on a cloud?', 'text', NULL, 'None', 'None of the current heroes float on a "cloud" as their base design, though some have cloud-themed skins.'),
('badminton', 'Shuttlecock', 'Which country is the largest producer of feather shuttlecocks?', 'text', NULL, 'China', 'Most professional goose-feather shuttles are manufactured in China.'),
('mobile legends', 'Item Passive', 'Which item provides the most "Magic Power" in a single slot?', 'multiple_choice', '["Holy Crystal", "Blood Wings", "Divine Glaive", "Genius Wand"]', 'Blood Wings', 'Blood Wings provides a massive flat amount of Magic Power and extra HP.');
INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 5: QUESTIONS 301 - 400
('badminton', 'Umpire Call', 'What does the umpire call when a player successfully challenges a line call using Instant Review?', 'text', NULL, 'Correction', 'If the review shows the line judge was wrong, the umpire announces "Correction" and updates the score.'),
('mobile legends', 'Hero Roles', 'Which hero is known as the "Land of Dawn''s first Fighter" in release history?', 'text', NULL, 'Alucard', 'Originally named Dante, Alucard was one of the earliest fighters introduced to the game.'),
('badminton', 'Racket Tension', 'Higher string tension makes the racket more "durable".', 'boolean', NULL, 'False', 'Higher tension puts more stress on the strings, causing them to snap more easily than lower tension.'),
('mobile legends', 'Item Passive', 'Which item provides the "Unique Passive: Mark," which increases the damage of the user''s next basic attack after a skill?', 'multiple_choice', '["Endless Battle", "Great Dragon Spear", "None", "Thunder Belt"]', 'Endless Battle', 'Endless Battle''s "Divine Justice" passive provides a true damage proc on the next basic attack.'),
('badminton', 'History', 'In what year was the International Badminton Federation (IBF) founded?', 'text', NULL, '1934', 'The IBF was established in 1934 before being renamed to the BWF in 2006.'),
('mobile legends', 'Hero Passive', 'Which hero can "absorb" the gold of a nearby turret shield without being the one to hit it?', 'text', NULL, 'None', 'Turret shield gold is only granted to heroes within a certain radius, regardless of who deals the final blow.'),
('badminton', 'Technique', 'The "Net Kill" is hit with a flat or slightly downward angle.', 'boolean', NULL, 'True', 'A net kill aims to strike the shuttle as it crosses the net to end the point instantly.'),
('mobile legends', 'Hero Lore', 'Which hero is a "Ninja" from the Scarlet Sect and rival of Hanzo?', 'text', NULL, 'Hayabusa', 'Hayabusa is the shadow ninja tasked with hunting down the traitor Hanzo.'),
('badminton', 'Famous Players', 'Carolina Marin is a multiple-time World Champion from which country?', 'text', NULL, 'Spain', 'Marin is the first European woman to win an Olympic gold medal in badminton.'),
('mobile legends', 'Item Counter', 'Which item is best for countering "Physical Penetration" from assassins?', 'multiple_choice', '["Antique Cuirass", "Blade Armor", "Dominance Ice", "Brute Force Breastplate"]', 'Antique Cuirass', 'It reduces the enemy''s Physical Attack by a percentage, mitigating the impact of their penetration stats.'),
('badminton', 'Service Area', 'In singles, the long service line is the same as the back boundary line.', 'boolean', NULL, 'True', 'Unlike doubles, singles players can serve all the way to the very back of the court.'),
('mobile legends', 'Hero Passive', 'Which hero uses "Energy" instead of Mana and has an ultimate called "Death Sonata"?', 'text', NULL, 'Granger', 'Granger is a marksman who relies on energy and high burst damage from his violin-case cannon.'),
('badminton', 'Shuttlecock', 'What is the "skirt" of a professional shuttlecock made of?', 'multiple_choice', '["Plastic", "Nylon", "Natural Feathers", "Silk"]', 'Natural Feathers', 'A professional shuttlecock consists of 16 overlapping feathers, usually from a goose.'),
('mobile legends', 'Game Mechanics', 'How many "stars" are deducted for a loss in the Legend rank?', 'text', NULL, '1', 'Players lose one star per loss unless they have active star protection.'),
('badminton', 'Double Strategy', 'The "T-Junction" is a high-priority target for which shot?', 'multiple_choice', '["Smash", "Short Serve", "Clear", "Drive"]', 'Short Serve', 'Serving at the T-junction minimizes the angles available to the receiver.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Queen of the Necrokeep"?', 'text', NULL, 'Vexana', 'Vexana is the ruler of the cursed Necrokeep and can summon undead knights.'),
('badminton', 'Terminology', 'What is a "Flick" shot?', 'text', NULL, 'A quick wrist-driven shot intended to surprise the opponent', 'A flick uses sudden acceleration from the wrist to change the trajectory of the shuttle.'),
('mobile legends', 'Item Passive', 'Which item is best for mages to reduce enemy "Magic Defense"?', 'multiple_choice', '["Genius Wand", "Holy Crystal", "Divine Glaive", "Glowing Wand"]', 'Genius Wand', 'Genius Wand provides flat magic penetration and reduces the enemy''s magic defense on hit.'),
('badminton', 'Racket Grip', 'A "G5" grip is smaller in circumference than a "G4" grip.', 'boolean', NULL, 'True', 'In badminton handle sizing, higher numbers represent smaller/thinner grips.'),
('mobile legends', 'Hero Skills', 'Which hero has an ultimate that "marks" enemies and allows him to dash through them repeatedly?', 'text', NULL, 'Lancelot', 'Lancelot’s "Puncture" (S1) resets its cooldown if he hits an unmarked target, though his ultimate is a straight-line dash.'),
('badminton', 'Match Structure', 'How long is the official break between the second and third games?', 'text', NULL, '120 seconds', 'BWF rules allow for a 2-minute break between games.'),
('mobile legends', 'Item Counter', 'Which item is most effective at slowing down enemies who rely on "Basic Attacks"?', 'multiple_choice', '["Dominance Ice", "Blade Armor", "Antique Cuirass", "Athena''s Shield"]', 'Dominance Ice', 'It reduces the attack speed of nearby enemies, directly hindering basic-attack-heavy heroes.'),
('badminton', 'History', 'Where was the first "Thomas Cup" tournament held?', 'text', NULL, 'Preston, England', 'The inaugural Thomas Cup took place in 1948-1949.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Tank" that can suppress an enemy by "eating" them?', 'text', NULL, 'Barats', 'Barats'' ultimate, "Detona''s Welcome," allows him to devour and then spit out an enemy hero.'),
