INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 7: QUESTIONS 501 - 600
('badminton', 'Umpire Equipment', 'What color card does a badminton umpire use to signal a player''s disqualification?', 'multiple_choice', '["Yellow", "Red", "Black", "Blue"]', 'Black', 'A black card is used to disqualify a player; yellow is a warning and red is a fault/point for the opponent.'),
('mobile legends', 'Hero Passive', 'Which hero is known as the "Wandering Sword" and is the brother of Lancelot?', 'text', NULL, 'None', 'Lancelot is an only child in the lore; Gusion has brothers (like Aamon), but no hero is Lancelot''s brother.'),
('badminton', 'Shuttlecock Speed', 'Shuttlecocks fly faster at higher altitudes.', 'boolean', NULL, 'True', 'Thinner air at higher altitudes provides less resistance, making the shuttlecock travel significantly faster.'),
('mobile legends', 'Item Passive', 'Which item provides the "Unique Passive: Mark" which increases the Physical Attack of the user upon hitting an enemy?', 'multiple_choice', '["War Axe", "Great Dragon Spear", "None", "Blade of Heptaseas"]', 'None', 'War Axe provides "Fighting Spirit" stacks; there is no item with a passive simply named "Mark" for attack.'),
('badminton', 'Technique', 'The "Cross-court Smash" travels a shorter distance than a straight smash.', 'boolean', NULL, 'False', 'A diagonal (cross-court) path is always longer than a straight path on a rectangular court.'),
('mobile legends', 'Hero Lore', 'Which hero is a "Spirit of the Forest" and the creator of Grock?', 'text', NULL, 'None', 'Grock belongs to an ancient race of Stone Titans; Belerick is a Spirit of the Forest but did not create Grock.'),
('badminton', 'Racket Grip', 'A "G5" grip size is the most common size used in Asia.', 'boolean', NULL, 'True', 'G5 (smaller) is popular in Asia, whereas G4 (larger) is more common in Western markets.'),
('mobile legends', 'Game Mechanics', 'How much "Shield" does a hero gain from the "Aegis" battle spell at Level 1?', 'multiple_choice', '["500", "750", "Scaling with Level", "1000"]', 'Scaling with Level', 'The shield amount scales as the hero levels up, ensuring it remains useful throughout the match.'),
('badminton', 'Famous Events', 'Which city hosts the BWF World Tour Finals for the 2023-2026 cycle?', 'text', NULL, 'Hangzhou', 'Hangzhou, China, was selected as the host for the season-ending finals for this four-year term.'),
('mobile legends', 'Item Passive', 'The "Calamity Reaper" and "Azure Blade" were merged into which item?', 'text', NULL, 'Starlium Scythe', 'Following the 2023 item revamp, these were combined to streamline magic true-damage builds.'),
('badminton', 'Service Area', 'In doubles, is it a fault if the server''s partner stands in a way that blocks the receiver''s view?', 'boolean', NULL, 'True', 'The server''s partner may stand anywhere, but they must not obstruct the receiver''s sight of the server.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Marksman" that uses "Energy" instead of Mana?', 'text', NULL, 'Lesley', 'Lesley uses Energy for her sniping skills, whereas heroes like Miya or Layla use Mana.'),
('badminton', 'Racket Tension', 'Strings lose tension even if the racket is not being used.', 'boolean', NULL, 'True', 'Nylon and natural gut strings gradually lose their elasticity over time due to the constant pull on the frame.'),
('mobile legends', 'Hero Lore', 'Which hero was a "General" from a foreign land inspired by historical Korean figures?', 'text', NULL, 'Yi Sun-shin', 'He is based on the famous Korean naval commander and utilizes both a bow and a glaive.'),
('badminton', 'Match Structure', 'A player is allowed to receive coaching during a rally.', 'boolean', NULL, 'False', 'Coaching is only permitted when the shuttle is not in play or during intervals.'),
('mobile legends', 'Item Counter', 'Which item is best for countering "Physical Penetration" from assassins?', 'multiple_choice', '["Antique Cuirass", "Blade Armor", "Dominance Ice", "Oracle"]', 'Antique Cuirass', 'It reduces the enemy''s Physical Attack, which effectively mitigates the impact of their penetration stats.'),
('badminton', 'History', 'Badminton is named after the estate of the Duke of Beaufort.', 'boolean', NULL, 'True', 'Badminton House in Gloucestershire is where the game was famously played and refined.'),
('mobile legends', 'Hero Roles', 'A "Jungler" gains less experience from minions during the first 5 minutes of the game.', 'boolean', NULL, 'True', 'This ensures the Jungler stays in the jungle and doesn''t take resources from the laners early on.'),
('badminton', 'Racket Parts', 'The "Ferrule" of a badminton racket is located where?', 'multiple_choice', '["At the tip", "Between the handle and shaft", "Inside the strings", "On the grip"]', 'Between the handle and shaft', 'The ferrule (or cone) covers the connection where the shaft meets the handle.'),
('mobile legends', 'Hero Lore', 'Gusion is a member of the "Paxley" family.', 'boolean', NULL, 'True', 'The Paxleys are a prestigious noble family in the Moniyan Empire known for magic.'),
('badminton', 'Service Fault', 'It is a fault if the server misses the shuttle entirely while attempting to serve.', 'boolean', NULL, 'True', 'A swing and a miss counts as a service fault and the opponent gains the point.'),
('mobile legends', 'Item Passive', 'Which item provides the highest "Attack Speed" in the game?', 'multiple_choice', '["Windtalker", "Golden Staff", "Corrosion Scythe", "Demon Hunter Sword"]', 'Golden Staff', 'Golden Staff provides a massive +65% attack speed at max stacks.'),
('badminton', 'Tournament Types', 'The "Thomas Cup" is held every four years.', 'boolean', NULL, 'False', 'The Thomas and Uber Cups are biennial events, held every two years.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Son of the Dragon"?', 'text', NULL, 'Zilong', 'Zilong is the commander of the Great Dragon''s forces in the Cadia Riverlands.'),
('badminton', 'Technique', 'A "Flick" shot is primarily generated by the shoulder.', 'boolean', NULL, 'False', 'A flick is a quick movement generated mostly by a snap of the wrist and forearm.'),
('mobile legends', 'Battle Spell', 'The "Retribution" spell can be used to deal damage to enemy heroes.', 'boolean', NULL, 'True', 'Once the Jungler upgrades their jungle boots, Retribution can be used on heroes to deal damage and slow them.'),
('badminton', 'Equipment', 'What is the "Skirt" of a shuttlecock made of?', 'multiple_choice', '["Cork", "Nylon/Feathers", "Leather", "Silk"]', 'Nylon/Feathers', 'The skirt is the cone part made of either 16 goose feathers or a single nylon mold.'),
('mobile legends', 'Hero Lore', 'Who is the "King of the Fire Demons" in the Abyss?', 'text', NULL, 'Thamuz', 'Thamuz is the leader of the fire demons and the rival of Dyrroth.'),
('badminton', 'Technique', 'The "Ready Stance" involves standing with your feet wide and knees slightly bent.', 'boolean', NULL, 'True', 'This athletic position allows for the fastest possible reaction to the opponent''s shot.'),
