('badminton', 'History', 'Where was the first Badminton World Championships held?', 'text', NULL, 'Malmö, Sweden', 'The inaugural championships took place in 1977.'),
('mobile legends', 'Gameplay', 'What is the maximum number of "Stars" a player can have in Mythic rank?', 'text', NULL, 'Unlimited', 'While names like Mythic Glory (50+) and Immortal (100+) exist, stars can be accumulated indefinitely.'),
('badminton', 'Technique', 'The "Scissors Kick" is used during a jump smash.', 'boolean', NULL, 'True', 'The legs swap positions in mid-air to generate power and ensure a balanced landing.'),
('mobile legends', 'Hero Passive', 'Which hero can "link" enemies to share damage?', 'text', NULL, 'Carmilla', 'Her ultimate "Curse of Blood" links enemies together.'),
