('badminton', 'Rule Fault', 'It is a fault if the shuttle hits the ceiling.', 'boolean', NULL, 'True', 'The ceiling is considered out of bounds.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Iron Chip"?', 'text', NULL, 'Chip', 'The portal-using support hero released in early 2024.'),
('badminton', 'History', 'Badminton has been in the Olympics since 1992.', 'boolean', NULL, 'True', 'It debuted as a medal sport at the Barcelona Games.'),
('mobile legends', 'Gameplay', 'The "Turtle" spawns every 2 minutes.', 'boolean', NULL, 'True', 'The Turtle respawns every 120 seconds after being killed.'),
('badminton', 'Famous Players', 'Who is known as the "King of Backhand"?', 'text', NULL, 'Taufik Hidayat', 'The Indonesian legend was famous for his powerful backhand smashes.'),
('mobile legends', 'Item Passive', 'The "Winter Truncheon" freeze lasts for 2 seconds.', 'boolean', NULL, 'True', 'The active effect "Frozen" lasts exactly 2 seconds.'),
('badminton', 'Double Rule', 'Partners must alternate hits in badminton doubles.', 'boolean', NULL, 'False', 'Unlike table tennis, any partner can hit the shuttle in any order.'),
