INSERT INTO filler_questions (topic, summary, text, type, options, correct_answer, explanation) VALUES
-- BATCH 8: QUESTIONS 601 - 700
('badminton', 'Umpire Call', 'What does the Umpire call to start the very first point of a match?', 'text', NULL, '0-0, Play', 'The Umpire announces the score as 0-0 followed by the command "Play".'),
('mobile legends', 'Hero Roles', 'Which hero is a "Support" that can transform an enemy into a "Cat" (Molina)?', 'text', NULL, 'Nana', 'Nana''s second skill, Molina Smooch, transforms an enemy into a small creature, preventing them from using skills.'),
('badminton', 'Racket Physics', 'What is "Torque" in a badminton racket?', 'multiple_choice', '["The weight of the head", "The twisting of the racket shaft", "The tension of the strings", "The length of the handle"]', 'The twisting of the racket shaft', 'Torque refers to how much the racket head twists during a hit; high-end rackets aim for low torque for better accuracy.'),
('mobile legends', 'Item Passive', 'Which item provides the "Unique Passive: Valor" which increases Physical Attack after a kill?', 'multiple_choice', '["Hunter Strike", "None", "Blade of Despair", "War Axe"]', 'None', 'There is no current item with a passive named "Valor"; Blade of Despair provides "Despair" which triggers based on HP thresholds.'),
('badminton', 'History', 'In which decade was the first-ever Thomas Cup held?', 'text', NULL, '1940s', 'The first Thomas Cup took place in the 1948–1949 season.'),
('mobile legends', 'Hero Lore', 'Which hero is the "Goddess of Flowers" and a companion of Belerick?', 'text', NULL, 'Floryn', 'Floryn was born from a seedling in the Oasis and is a healer associated with nature.'),
('badminton', 'Technique', 'The "Cross-court Underhand Clear" is hit from the net to the backcourt.', 'boolean', NULL, 'True', 'It is a defensive shot hit diagonally to move the opponent to the furthest corner.'),
('mobile legends', 'Hero Passive', 'Which hero can "resurrect" an ally by turning them into a "Ghost" temporarily?', 'text', NULL, 'Faramis', 'Faramis'' ultimate, Cult Altar, provides a temporary extra life to allies within its range.'),
('badminton', 'Famous Players', 'Viktor Axelsen is the first European to win two Olympic Gold medals in Men''s Singles.', 'boolean', NULL, 'True', 'He won gold at Tokyo 2020 and successfully defended his title at Paris 2024.'),
('mobile legends', 'Item Counter', 'Which item is best for reducing the "Critical Damage" taken from a marksman?', 'multiple_choice', '["Blade Armor", "Antique Cuirass", "Twilight Armor", "Dominance Ice"]', 'Blade Armor', 'Blade Armor has a unique passive that reduces incoming Critical Damage by 20%.'),
('badminton', 'Service Area', 'In singles, if the server''s score is 0, they serve from the right side.', 'boolean', NULL, 'True', 'Zero is treated as an even number, designating the right service court.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Mage" that uses "Gusion''s Daggers" but is actually an Assassin?', 'text', NULL, 'Gusion', 'Gusion is officially classified as an Assassin/Mage and uses throwing daggers to burst down enemies.'),
('badminton', 'Shuttlecock Parts', 'What bird''s feathers are most commonly used in professional shuttlecocks?', 'multiple_choice', '["Chicken", "Goose", "Duck", "Swan"]', 'Goose', 'Goose feathers are the standard for high-level tournament play due to their durability and flight path.'),
('mobile legends', 'Game Mechanics', 'What is the "Active" skill name of the "Wind of Nature" item?', 'text', NULL, 'Wind of Nature', 'The item and the skill share the same name; it grants immunity to all physical damage for 2 seconds (1s for non-Marksmen).'),
('badminton', 'History', 'Which country has won the most recent Uber Cup (2024)?', 'text', NULL, 'China', 'China defeated Indonesia in the 2024 final to secure their 16th title.'),
('mobile legends', 'Item Passive', 'The "Fleeting Time" item reduces the cooldown of which skill?', 'multiple_choice', '["Skill 1", "Skill 2", "Ultimate", "Passive"]', 'Ultimate', 'The Timestream passive reduces the Ultimate cooldown by 30% after a kill or assist.'),
('badminton', 'Racket Tension', 'Thicker strings (higher gauge) provide better "Control" than thinner strings.', 'boolean', NULL, 'False', 'Thinner strings provide better feel and control; thicker strings provide durability.'),
('mobile legends', 'Hero Passive', 'Which hero is an "Assassin" that uses "Cables" to move across the map?', 'text', NULL, 'Fanny', 'Fanny is unique for her Steel Cable mechanic, requiring high energy management.'),
('badminton', 'Technique', 'A "Kill" shot is always hit from the back of the court.', 'boolean', NULL, 'False', 'A "Net Kill" is an aggressive shot hit from the front of the court, very close to the net.'),
('mobile legends', 'Hero Roles', 'Which hero is a "Tank" that can suppress an enemy by "tying" them with a rope?', 'text', NULL, 'Kaja', 'Kaja’s ultimate, Divine Judgment, suppresses and pulls an enemy toward his team.'),
('badminton', 'Racket Material', 'High-modulus graphite is a common material for professional rackets.', 'boolean', NULL, 'True', 'It provides the necessary stiffness and strength to handle high string tensions.'),
('mobile legends', 'Item Passive', 'Which item provides the highest amount of "Physical Penetration"?', 'multiple_choice', '["Malefic Roar", "Hunter Strike", "Heptaseas", "War Axe"]', 'Malefic Roar', 'Malefic Roar scales its penetration based on the enemy''s physical defense.'),
('badminton', 'Scoring', 'If a match is 1-1 in games, how many points are needed to win the third game?', 'text', NULL, '21', 'The deciding third game is played to the standard 21 points.'),
('mobile legends', 'Hero Lore', 'Which hero is known as the "Spear of Dragon"?', 'text', NULL, 'Zilong', 'Zilong is the commander of the Great Dragon''s forces in the Cadia Riverlands.'),
('badminton', 'Technique', 'A "Flick Serve" is hit with a fast, sudden snap of the wrist.', 'boolean', NULL, 'True', 'The goal is to surprise the opponent by sending the shuttle deep to the backcourt.'),
('mobile legends', 'Item Passive', 'The "Demon Hunter Sword" deals damage based on the enemy''s Current HP.', 'boolean', NULL, 'True', 'Its passive, Devour, deals 9% of the target''s current HP as physical damage.'),
('badminton', 'Equipment', 'A "Synthetic" shuttlecock is usually made from which material?', 'multiple_choice', '["Rubber", "Nylon", "Cotton", "Silk"]', 'Nylon', 'Nylon shuttlecocks are the standard for training and recreational play.'),
('mobile legends', 'Hero Lore', 'Who is the "Prince of the Abyss"?', 'text', NULL, 'Dyrroth', 'Dyrroth is the younger brother of Silvanna, kidnapped and corrupted by the Abyss.'),
